# Dotted Surface

A Three.js-powered full-screen animated background that renders a 40×60 grid of 3D particles oscillating in sine wave patterns. Particle color adapts to light/dark theme via next-themes. Positioned as a fixed `z-[-1]` layer behind page content.

## Use when
- Building a SaaS or tech product landing page with an animated 3D dot-wave background.
- Adding depth to a light/dark theme page with a particle grid that responds to theme changes.
- Creating an immersive background for a hero or fullscreen section.
- Showcasing a data-driven or scientific product with a wave particle aesthetic.

## Stack
- Framework: react
- Libraries: three, next-themes
- Requires: tailwind, shadcn

## Install
```bash
three next-themes
```

## Component — dotted-surface.tsx
```tsx
'use client';
import { cn } from '@/lib/utils';
import { useTheme } from 'next-themes';
import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';

type DottedSurfaceProps = Omit<React.ComponentProps<'div'>, 'ref'>;

export function DottedSurface({ className, ...props }: DottedSurfaceProps) {
	const { theme } = useTheme();
	const containerRef = useRef<HTMLDivElement>(null);
	const sceneRef = useRef<{
		scene: THREE.Scene;
		camera: THREE.PerspectiveCamera;
		renderer: THREE.WebGLRenderer;
		particles: THREE.Points[];
		animationId: number;
		count: number;
	} | null>(null);

	useEffect(() => {
		if (!containerRef.current) return;
		const SEPARATION = 150; const AMOUNTX = 40; const AMOUNTY = 60;
		const scene = new THREE.Scene();
		scene.fog = new THREE.Fog(0xffffff, 2000, 10000);
		const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 1, 10000);
		camera.position.set(0, 355, 1220);
		const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
		renderer.setPixelRatio(window.devicePixelRatio);
		renderer.setSize(window.innerWidth, window.innerHeight);
		renderer.setClearColor(scene.fog.color, 0);
		containerRef.current.appendChild(renderer.domElement);
		const positions: number[] = []; const colors: number[] = [];
		const geometry = new THREE.BufferGeometry();
		for (let ix = 0; ix < AMOUNTX; ix++) {
			for (let iy = 0; iy < AMOUNTY; iy++) {
				positions.push(ix * SEPARATION - (AMOUNTX * SEPARATION) / 2, 0, iy * SEPARATION - (AMOUNTY * SEPARATION) / 2);
				if (theme === 'dark') colors.push(200, 200, 200); else colors.push(0, 0, 0);
			}
		}
		geometry.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
		geometry.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
		const material = new THREE.PointsMaterial({ size: 8, vertexColors: true, transparent: true, opacity: 0.8, sizeAttenuation: true });
		const points = new THREE.Points(geometry, material);
		scene.add(points);
		let count = 0; let animationId: number;
		const animate = () => {
			animationId = requestAnimationFrame(animate);
			const posAttr = geometry.attributes.position;
			const pos = posAttr.array as Float32Array;
			let i = 0;
			for (let ix = 0; ix < AMOUNTX; ix++) for (let iy = 0; iy < AMOUNTY; iy++) { pos[i * 3 + 1] = Math.sin((ix + count) * 0.3) * 50 + Math.sin((iy + count) * 0.5) * 50; i++; }
			posAttr.needsUpdate = true;
			renderer.render(scene, camera);
			count += 0.1;
		};
		const handleResize = () => { camera.aspect = window.innerWidth / window.innerHeight; camera.updateProjectionMatrix(); renderer.setSize(window.innerWidth, window.innerHeight); };
		window.addEventListener('resize', handleResize);
		animate();
		sceneRef.current = { scene, camera, renderer, particles: [points], animationId, count };
		return () => {
			window.removeEventListener('resize', handleResize);
			if (sceneRef.current) {
				cancelAnimationFrame(sceneRef.current.animationId);
				sceneRef.current.scene.traverse(obj => { if (obj instanceof THREE.Points) { obj.geometry.dispose(); (Array.isArray(obj.material) ? obj.material : [obj.material]).forEach(m => m.dispose()); } });
				sceneRef.current.renderer.dispose();
				if (containerRef.current && sceneRef.current.renderer.domElement) containerRef.current.removeChild(sceneRef.current.renderer.domElement);
			}
		};
	}, [theme]);

	return <div ref={containerRef} className={cn('pointer-events-none fixed inset-0 -z-1', className)} {...props} />;
}
```

## Demo
```tsx
import { DottedSurface } from "@/components/ui/dotted-surface";
import { cn } from '@/lib/utils';

export default function DemoOne() {
  return (
    <DottedSurface className="size-full">
      <div className="absolute inset-0 flex items-center justify-center">
        <div
          aria-hidden="true"
          className={cn('pointer-events-none absolute -top-10 left-1/2 size-full -translate-x-1/2 rounded-full', 'bg-[radial-gradient(ellipse_at_center,--theme(--color-foreground/.1),transparent_50%)]', 'blur-[30px]')}
        />
        <h1 className="font-mono text-4xl font-semibold">Dotted Surface</h1>
      </div>
    </DottedSurface>
  );
}
```

## Notes
- Requires `next-themes` for theme detection. Wrap your app in `ThemeProvider` from `next-themes`.
- The renderer re-initializes on theme change (the `useEffect` depends on `[theme]`) which causes a brief flicker — this is by design to rebuild particle colors.
